"use strict";parserFactory.register("hui3r.wordpress.com",()=>new Hui3rParser);class Hui3rParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.single-entry-content ul a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.single-entry-content")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"#jp-post-flair, footer.entry-meta"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector(".entry-title")}}